import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/installer-screen.Db0E_BrK.js";import{t as a}from"./chunks/launcher-screen.B4Y3DSWp.js";import{t as o}from"./chunks/macos-settings.e7FrcLCc.js";const s=JSON.parse(`{"title":"Instalando o Fabric no macOS","description":"Um guia passo a passo de como instalar o Fabric no macOS.","frontmatter":{"title":"Instalando o Fabric no macOS","description":"Um guia passo a passo de como instalar o Fabric no macOS.","authors":["Benonardo","ezfe","IMB11","modmuss50"],"next":false,"files":[]},"headers":[],"relativePath":"pt_br/players/installing-fabric/macos.md","filePath":"translated/pt_br/players/installing-fabric/macos.md","lastUpdated":1770561656000}`);var c={name:`pt_br/players/installing-fabric/macos.md`};function l(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Instalando o Fabric no macOS <a class="header-anchor" href="#h1" aria-label="Permalink to “Instalando o Fabric no macOS”">​</a></h1><div class="info custom-block"><p class="custom-block-title">PRÉ-REQUISITOS</p><p>Você pode precisar <a href="./../installing-java/macos">instalar o Java</a> antes de executar o <code>.jar</code>.</p></div><h2 id="1-download-the-fabric-installer" tabindex="-1">1. Baixar o instalador do Fabric <a class="header-anchor" href="#1-download-the-fabric-installer" aria-label="Permalink to “1. Baixar o instalador do Fabric”">​</a></h2><p>Baixe a versão do <code>.jar</code> do instalador do Fabric direto do <a href="https://fabricmc.net/use/" target="_blank" rel="noreferrer">Site do Fabric</a>, clicando em &quot;Download installer (Universal/.JAR)&quot;.</p><h2 id="2-run-the-fabric-installer" tabindex="-1">2. Execute o Instalador do Fabric <a class="header-anchor" href="#2-run-the-fabric-installer" aria-label="Permalink to “2. Execute o Instalador do Fabric”">​</a></h2><p>Feche o Minecraft e o Iniciador antes de executar o Instalador.</p><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>Você pode receber um aviso de que a Apple não pode verificar o arquivo <code>.jar</code>. Para contorná-lo, abra &quot;Ajustes do Sistema&quot; &gt; &quot;Privacidade e Segurança&quot;, então, clique em <code>Abrir mesmo assim</code>. Confirme e digite sua Senha de Administrador, se for pedido.</p><p><img src="/assets/players/installing-fabric/macos-settings.png" alt="Ajustes do Sistema do macOS" loading="lazy"></p></div><p>Assim que você abrir o instalador, você deveria ver uma tela como essa:</p><p><img src="/assets/players/installing-fabric/installer-screen.png" alt="O instalador do Fabric com &quot;Install&quot; destacado" loading="lazy"></p><p>Selecione a sua versão escolhida de Minecraft e clique em <code>Install</code>. Certifique-se de que o campo <code>Create Profile</code> está marcado.</p><h3 id="installing-via-homebrew" tabindex="-1">Faça a instalação via Homebrew <a class="header-anchor" href="#installing-via-homebrew" aria-label="Permalink to “Faça a instalação via Homebrew”">​</a></h3><p>Se você já tiver o <a href="https://brew.sh" target="_blank" rel="noreferrer">Homebrew</a> instalado, você pode instalar o Fabric usando <code>brew</code>:</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">brew</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> fabric-installer</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="3-finish-setup" tabindex="-1">3. Finalize a instalação <a class="header-anchor" href="#3-finish-setup" aria-label="Permalink to “3. Finalize a instalação”">​</a></h2><p>Uma vez que a instalação esteja completa, abra o Iniciador do Minecraft. Então, selecione o perfil do Fabric no menu suspenso e clique em Jogar.</p><p><img src="/assets/players/installing-fabric/launcher-screen.png" alt="O Iniciador de Minecraft com o perfil do Fabric selecionado" loading="lazy"></p><p>Você pode agora, adicionar mods ao seu jogo. Veja o guia <a href="./../finding-mods">Encontrando Mods Confiáveis</a> para mais informações.</p><p>Se você encontrar problemas, sinta-se a vontade para pedir ajuda em <a href="https://discord.fabricmc.net/" target="_blank" rel="noreferrer">Discord do Fabric</a> no canal <code>#player-support</code>.</p>`,18)]])}var u=r(c,[[`render`,l]]);export{s as __pageData,u as default};